27	const PROCESSING_FEE = 5;
28	const FIRST_CONTRACT_SURCHARGE_RATE = 0.1;
29	
30	const BASE_PREMIUM: Record<string, number> = {
31	  sword: 100,
32	  amulet: 60,
33	  staff: 80,
34	  potion: 40,
35	  rune: 25,
36	};
37	
38	const sumBasePremiums = (items: Item[]): number =>
39	  items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
40	
41	const quote = (step: QuoteStep): QuoteResult => {
42	  const itemsBase = sumBasePremiums(step.items);
43	  const firstContractSurcharge = itemsBase * FIRST_CONTRACT_SURCHARGE_RATE;
44	  return { premium: itemsBase + firstContractSurcharge + PROCESSING_FEE };
45	};
46	
47	export const runScenario = (scenario: Scenario): ScenarioResult => {
48	  const results = scenario.steps.map(quote);
49	  return { results };
